(window.webpackJsonp=window.webpackJsonp||[]).push([[338],{965:function(n,r){n.exports='\x3c!-- \r\ntitle: ZSH\r\nsort: \r\n--\x3e \r\n# zsh安装与配置\r\n\r\n## 安装\r\n\r\n```bash\r\n# sudo pacman -S zsh\r\nchsh -s /usr/bin/zsh\t\t# 切换zsh /bin/zsh\r\n# 安装oh-my-zsh\r\nsh -c "$(curl -fsSL https://raw.githubusercontent.com/robbyrussell/oh-my-zsh/master/tools/install.sh)"\r\n```\r\n\r\n## 配置主题\r\n\r\n```bash\r\nkate ~/.zshrc\r\n# 解决问题\r\n[+] ZSH_DISABLE_COMPFIX=true\r\n# ZSH_THEME=random\t# 随机主题\r\n# p10k\r\ngit clone --depth=1 https://github.com/romkatv/powerlevel10k.git ${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/themes/powerlevel10k\r\nZSH_THEME="powerlevel10k/powerlevel10k"\r\n# 重新加载zsh\r\nsource .zshrc\r\n```\r\n\r\n## 插件\r\n\r\n```bash\r\n# zsh-syntax-highlighting\r\n# 命令行高亮\r\ngit clone https://github.com/zsh-users/zsh-syntax-highlighting.git ${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/plugins/zsh-syntax-highlighting\r\n# zsh-autosuggestions\r\n# 记住你之前使用过的命令\r\ngit clone git://github.com/zsh-users/zsh-autosuggestions $ZSH_CUSTOM/plugins/zsh-autosuggestions\r\n# autojump\r\n# 跳转目录\r\nyay -S autojump\r\n# 命令查找\r\nyay -S fzf\r\n# fuck\r\nyay -S thefuck\r\n# 插件管理器\r\ncurl -sL --proto-redir -all,https https://raw.githubusercontent.com/zplug/installer/master/installer.zsh | zsh\r\n# 字体安装\r\nhttps://www.nerdfonts.com/\r\n```\r\n\r\n- 配置文件\r\n\r\n  ```bash\r\n  ## 启用所有插件\r\n  nano ~/.zshrc\r\n  # 将plugins=(git)改为:\r\n  plugins=(git zsh-syntax-highlighting zsh-autosuggestions autojump sudo extract)\r\n  # sudo功能，在你输入的命令的开头添加sudo ，方法是双击Esc。\r\n  # extract +你要解压的文件名\r\n  # 在source $ZSH/oh-my-zsh.sh下面输入：\r\n  source ~/.oh-my-zsh/custom/plugins/incr/incr*.zsh\r\n  # 在文件末尾输入：\r\n  eval $(thefuck --alias)\r\n  # vscode font  设置\r\n  Hack Nerd Font\r\n  \r\n  ## clone\r\n  git clone https://github.com/fzf404/linux_config.git\r\n  ln linux_config/.zshrc .zhsrc\r\n  ```\r\n\r\n### 插件使用\r\n\r\n- git\r\n\r\n  ```bash\r\n  gapa    git add --patch\r\n  gc!    git commit -v --amend\r\n  gcl    git clone --recursive\r\n  gclean    git reset --hard && git clean -dfx\r\n  gcm    git checkout master\r\n  gcmsg    git commit -m\r\n  gco    git checkout\r\n  gd    git diff\r\n  gdca    git diff --cached\r\n  gp    git push\r\n  grbc    git rebase --continue\r\n  gst    git status\r\n  gup    git pull --rebase\r\n  ```\r\n\r\n- extract\r\n\r\n  > 解压文件，无需参数\r\n\r\n### 使用技巧\r\n\r\n- 命令历史记录\r\n\r\n  > 使用`r`来执行上一条命令\r\n  >\r\n  > 使用`Ctrl+R`搜索命令历史记录\r\n\r\n- 目录选择\r\n\r\n  > 连按两次`Tab`会列出所有的补全直接选择，可以使用 ctrl+n/p/f/b上下左右切换\r\n  >\r\n  > 使用`j folder`直接进行目录跳转\r\n  >\r\n  > `j --stat`查看历史路径库\r\n  >\r\n  >  `/usr/local/bin` 你可以输入` cd /u/l/b` 然后按/\r\n  >'}}]);